def validate(args, outputs):
    ops, arg_lists = args
    if not isinstance(outputs, list) or len(outputs) != len(ops):
        return False
    nums = arg_lists[0][0]
    for i in range(1, len(ops)):
        if ops[i] == 'pick':
            target = arg_lists[i][0]
            idx = outputs[i]
            if not isinstance(idx, int) or isinstance(idx, bool):
                return False
            if idx < 0 or idx >= len(nums):
                return False
            if nums[idx] != target:
                return False
    return True

