import random


class Solution:
    def __init__(self, nums):
        self.nums = nums
    def pick(self, target):
        result = -1
        count = 0
        for i, v in enumerate(self.nums):
            if v == target:
                count += 1
                if random.randint(1, count) == count:
                    result = i
        return result

